+using ShipmentTracker.Client.Models;
+using ShipmentTracker.Client.Services;
+
+namespace ShipmentTracker.Endpoints;
+
+public static class ShipmentEndpoints
+{
+    public static void MapShipmentEndpoints(this WebApplication app)
+    {
+        var group = app.MapGroup("/api/shipments");
+
+        group.MapGet("/", async (IShipmentService service) =>
+        {
+            var shipments = await service.GetAllShipmentsAsync();
+            return Results.Ok(shipments);
+        }).RequireAuthorization("Dispatcher");
+
+        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
+        {
+            var shipment = await service.GetShipmentByTrackingNumberAsync(trackingNumber);
+            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
+        }).RequireAuthorization();
+
+        group.MapGet("/customer/{email}", async (string email, IShipmentService service) =>
+        {
+            var shipments = await service.GetShipmentsByCustomerAsync(email);
+            return Results.Ok(shipments);
+        }).RequireAuthorization();
+
+        group.MapPost("/", async (Shipment shipment, IShipmentService service) =>
+        {
+            var created = await service.CreateShipmentAsync(shipment);
+            return Results.Created($"/api/shipments/track/{created.TrackingNumber}", created);
+        }).RequireAuthorization();
+
+        group.MapPut("/{id}/status", async (int id, ShipmentStatus status, IShipmentService service) =>
+        {
+            var updated = await service.UpdateShipmentStatusAsync(id, status);
+            return Results.Ok(updated);
+        }).RequireAuthorization();
+    }
+}
