@page "/track"
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track a Shipment</h1>

<div class="mb-4">
    <div class="input-group" style="max-width: 500px;">
        <input type="text" class="form-control" placeholder="Enter tracking number" @bind="trackingNumber" @bind:event="oninput" @onkeydown="HandleKeyDown" />
        <button class="btn btn-primary" @onclick="TrackShipment">Track</button>
    </div>
</div>

@if (isLoading)
{
    <p><em>Searching...</em></p>
}
else if (notFound)
{
    <div class="alert alert-warning">No shipment found with tracking number "@trackingNumber".</div>
}
else if (shipment is not null)
{
    <div class="card">
        <div class="card-header">
            <h4>Shipment @shipment.TrackingNumber</h4>
        </div>
        <div class="card-body">
            <div class="row mb-4">
                <div class="col-md-6">
                    <p><strong>Origin:</strong> @shipment.Origin</p>
                    <p><strong>Destination:</strong> @shipment.Destination</p>
                    <p><strong>Description:</strong> @shipment.Description</p>
                </div>
                <div class="col-md-6">
                    <p><strong>Shipped Date:</strong> @shipment.ShippedDate.ToString("MMM dd, yyyy")</p>
                    <p><strong>Estimated Delivery:</strong> @shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</p>
                    @if (shipment.ActualDelivery.HasValue)
                    {
                        <p><strong>Actual Delivery:</strong> @shipment.ActualDelivery.Value.ToString("MMM dd, yyyy")</p>
                    }
                </div>
            </div>

            <!-- Status Timeline -->
            <h5>Status Progress</h5>
            <div class="d-flex justify-content-between position-relative mt-3 mb-3">
                <div class="position-absolute top-50 start-0 end-0" style="height: 4px; background: #dee2e6; z-index: 0;"></div>
                <div class="position-absolute top-50 start-0" style="height: 4px; background: #0d6efd; z-index: 1; width: @(GetProgressPercent())%;"></div>
                @foreach (var step in statusSteps)
                {
                    var isActive = (int)shipment.Status >= (int)step;
                    <div class="text-center position-relative" style="z-index: 2;">
                        <div class="rounded-circle mx-auto @(isActive ? "bg-primary" : "bg-secondary")" style="width: 20px; height: 20px;"></div>
                        <small class="d-block mt-1 @(isActive ? "fw-bold" : "text-muted")">@step</small>
                    </div>
                }
            </div>

            <div class="mt-3">
                <span class="badge bg-@GetStatusColor(shipment.Status) fs-6">Current: @shipment.Status</span>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = "";
    private Shipment? shipment;
    private bool isLoading;
    private bool notFound;

    private static readonly ShipmentStatus[] statusSteps =
    [
        ShipmentStatus.Pending,
        ShipmentStatus.PickedUp,
        ShipmentStatus.InTransit,
        ShipmentStatus.OutForDelivery,
        ShipmentStatus.Delivered
    ];

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isLoading = true;
        notFound = false;
        shipment = null;

        shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(trackingNumber.Trim());
        notFound = shipment is null;
        isLoading = false;
    }

    private async Task HandleKeyDown(Microsoft.AspNetCore.Components.Web.KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private int GetProgressPercent()
    {
        if (shipment is null) return 0;
        var idx = Array.IndexOf(statusSteps, shipment.Status);
        if (idx < 0) return 0;
        return idx * 100 / (statusSteps.Length - 1);
    }

    private static string GetStatusColor(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "secondary",
        ShipmentStatus.PickedUp => "info",
        ShipmentStatus.InTransit => "primary",
        ShipmentStatus.OutForDelivery => "warning",
        ShipmentStatus.Delivered => "success",
        ShipmentStatus.Delayed => "danger",
        _ => "secondary"
    };
}

